#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N, X, Y;
        scanf("%lld %lld %lld", &N, &X, &Y);
        if ((N + 1) * Y >= X) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

